// 统一的认证管理
import { storage } from './storage'
import request from './request'

export const authManager = {
  // 检查是否已登录
  isAuthenticated() {
    const auth = storage.getAuth()
    if (!auth) return false

    const now = new Date().getTime()
    return auth.expiration > now
  },

  // 获取当前token
  getToken() {
    const auth = storage.getAuth()
    return auth?.access
  },

  // 获取刷新token
  getRefreshToken() {
    const auth = storage.getAuth()
    return auth?.refresh
  },

  // 处理登录
  async login(credentials, remember = false) {
    const response = await request.post('/api/v1/users/auth/login/password/', credentials)

    if (response.data?.code === 200) {
      const { access, refresh } = response.data.data
      storage.saveAuth({ access, refresh }, remember)
      if (remember) {
        storage.savePhone(credentials.phone, true)
      }
    }

    return response
  },

  // 处理登出
  async logout() {
    const refresh = this.getRefreshToken()
    if (refresh) {
      try {
        await request.post('/api/v1/users/auth/logout/', { refresh })
      } catch (error) {
        if (error.response?.status !== 401) {
          throw error
        }
      }
    }
    storage.clearAuth()
  }
}
